import { IMessageEvent, MessageEvent } from '@nitrots/nitro-renderer/src/core';
import { SlotMachineStateParser } from '@nitrots/nitro-renderer/src/nitro/communication/messages/parser/SlotMachineStateParser';

export class SlotMachineStateEvent
    extends MessageEvent
    implements IMessageEvent
{
    constructor(callback: Function) {
        super(callback, SlotMachineStateParser);
        console.log('[🎰] SlotMachineStateEvent initialized');
    }

    public getParser(): SlotMachineStateParser {
        return this.parser as SlotMachineStateParser;
    }
}
